css:
/* ===== 字体导入 ===== */
@import url("https://fontsapi.zeoseven.com/190/main/result.css");

body {
  font-family: "极影毁片圆 Medium", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  font-weight: normal;
}

/* ===== 自定义文案 ===== */
.mes[is_user="false"] .mesAvatarWrapper::after,
.mes[is_user="true"] .mesAvatarWrapper::after {
  content: '@あたしが愛を語るのなら、';/* ===== ai文案 ===== */
  display: block;
  text-align: center;
  position: relative;
  z-index: 3;
  margin-top: var(--custom-text-margin);
  font-size: 12px;
  color: var(--深灰);
  font-weight: 500;
  width: 100% !important;
}
.mes[is_user="true"] .mesAvatarWrapper::after { content: '@自定义文案'; }/* ===== user文案 ===== */

/* ===== 一、全局控制 (夜间模式) ===== */
:root {
  /* 夜间模式配色 */
  --主色调: #121212; /* 深邃黑，作为基础背景 */
  --浅灰: #1e1e1e; /* 近黑的灰色，用于卡片、输入框等 */
  --中灰: #3c3c3c; /* 用于边框和分割线 */
  --深灰: #8e8e8e; /* 用于次要文本和图标 */
  --黑色: #e0e0e0; /* 亮灰色，用于主要文本 */
  --边框色: #2a2a2a; /* 更深的边框色 */
  --阴影色: rgba(0, 0, 0, 0.4); /* 更明显的阴影 */
  --ins蓝: #0095f6; /* 保持不变的强调色 */

  /* 可自定义区域 */
  --avatar-top-padding: 40px; /* 头像距离顶部背景的距离 */
  --name-top-margin: 12px; /* 名字距离头像的距离 */
  --custom-text-margin: 8px; /* 自定义文案距离名字的距离 */
}

body {
  color: var(--黑色) !important;
  background-color: var(--主色调) !important;
}

.select2-container--default .select2-selection--multiple .select2-selection__choice {
  background-image: none !important;
  background-color: var(--浅灰) !important;
  border-color: var(--中灰) !important;
  color: var(--黑色) !important;
}

.text_pole {
  background-color: var(--浅灰);
}

/* ===== 二、顶栏 ===== */
#top-settings-holder {
  background-color: var(--浅灰) !important;
  border: none !important;
  border-bottom: 1px solid var(--边框色) !important;
  box-shadow: none !important;
  padding: 8px 12px !important;
}

#top-bar {
  background-color: transparent !important;
  box-shadow: none !important;
  border: none !important;
}

#top-settings-holder .drawer-icon::before {
  content: '' !important;
  visibility: hidden;
}

#top-settings-holder .drawer {
  flex: 1;
}

#top-settings-holder .drawer-icon {
  display: block;
  margin: 0 auto;
  background-size: contain;
  background-position: center;
  background-repeat: no-repeat;
  transition: all 0.2s ease;
  width: 22px;
  height: 22px;
  opacity: 1 !important;
  filter: invert(0.8); /* 反色处理，使图标在暗色背景下可见 */
}

.drawer-icon.fa-fw:hover {
  transform: scale(1.08);
  opacity: 0.6;
}

/* 9个顶栏图标 (已通过 filter 统一处理) */
#ai-config-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38efc5157e1a884ee6d9.png') !important; }
#sys-settings-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38eec5157e1a884ee6d4.png') !important; }
#advanced-formatting-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38eec5157e1a884ee6d1.png') !important; }
#WI-SP-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38efc5157e1a884ee6dd.png') !important; }
#user-settings-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38efc5157e1a884ee6de.png') !important; }
#logo_block .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38f4c5157e1a884ee6f4.png') !important; }
#extensions-settings-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de394cc5157e1a884ee919.png') !important; }
#persona-management-button .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de38eec5157e1a884ee6d4.png') !important; }
#rightNavHolder .drawer-icon { background-image: url('https://pic1.imgdb.cn/item/68de394dc5157e1a884ee91d.png') !important; }

/* ===== 三、底栏 ===== */
#send_form {
  background-color: var(--浅灰) !important;
  border-radius: 24px !important;
  border: 1px solid var(--边框色) !important;
  padding: 6px 10px !important;
  box-shadow: 0 2px 8px var(--阴影色) !important;
}

#send_textarea {
  border-radius: 20px !important;
  background-color: var(--主色调) !important;
  border: none !important;
  padding: 10px 16px !important;
  color: var(--黑色) !important;
  font-size: 13px !important;
}

#send_textarea::placeholder {
  color: var(--深灰) !important;
}

#send_form [class*="fa-"]::before {
  content: '' !important;
  display: inline-block;
  width: 24px;
  height: 24px;
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  vertical-align: middle;
  filter: invert(0.8); /* 反色处理 */
}

#options_button::before { background-image: url('https://pic1.imgdb.cn/item/68de3b3dc5157e1a884eed3c.png') !important; }
#extensionsMenuButton::before { background-image: url('https://pic1.imgdb.cn/item/68de3b3dc5157e1a884eed3b.png') !important; }
#send_but::before { background-image: url('https://pic1.imgdb.cn/item/68de3b3dc5157e1a884eed39.png') !important; }
#mes_stop i::before { background-image: url('https://pic1.imgdb.cn/item/68de3b3ec5157e1a884eed3d.png') !important; }

/* ===== 四、聊天区域 ===== */
#chat {
  backdrop-filter: none !important;
  padding: 16px 8px !important;
}

.mes {
  background: var(--浅灰) !important;
  border: 1px solid var(--边框色) !important;
  /* 保持其余样式不变 */
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
  gap: 0 !important;
  border-radius: 24px !important;
  padding: 0 !important;
  max-width: 614px !important;
  margin: 0 auto 48px auto !important;
  box-shadow: 0 2px 8px var(--阴影色) !important;
  overflow: visible !important;
  position: relative !important;
}

.mes .mesAvatarWrapper {
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
  justify-content: flex-start !important;
  gap: 0 !important;
  padding: 37px 37px 7px 37px !important;
  background-color: transparent !important;
  border: none !important;
  z-index: 2 !important;
  width: 100% !important;
  position: relative !important;
  box-sizing: border-box !important;
}

.mes .mesAvatarWrapper::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 140px;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  z-index: 1;
  border-radius: 24px 24px 0 0;
}

.mes[is_user="false"] .mesAvatarWrapper::before { background-image: url('https://pic1.imgdb.cn/item/68dfa323c5157e1a88543c66.png'); }
.mes[is_user="true"] .mesAvatarWrapper::before { background-image: url('https://pic1.imgdb.cn/item/68dfa387c5157e1a88543c74.png'); }

.mesAvatarWrapper .avatar {
  display: flex !important;
  justify-content: center !important;
  align-items: center !important;
  position: relative !important;
  z-index: 3 !important;
  pointer-events: none !important;
  padding-top: var(--avatar-top-padding) !important;
  width: auto !important;
  height: auto !important;
  max-width: 90px !important;
  max-height: 90px !important;
  aspect-ratio: 1 / 1 !important;
  flex-shrink: 0 !important;
}

.mes .avatar img {
  pointer-events: auto !important;
  width: 90px !important;
  height: 90px !important;
  min-width: 90px !important;
  min-height: 90px !important;
  border-radius: 50% !important;
  border: none !important;
  object-fit: cover !important;
  display: block !important;
  flex-shrink: 0 !important;
}

.name_text {
  color: var(--黑色) !important;
  /* 保持其余样式不变 */
  display: block !important;
  text-align: center !important;
  font-weight: 600 !important;
  font-size: 14px !important;
  z-index: 3 !important;
  position: relative !important;
  margin: var(--name-top-margin) 0 0 0 !important;
  width: 100% !important;
}

.tokenCounterDisplay, .mes_timer, .mesIDDisplay {
  color: var(--深灰) !important;
  /* 保持其余样式不变 */
  display: inline-block !important;
  font-size: 11px !important;
  z-index: 3 !important;
  position: relative !important;
  margin: 8px 4px 0 4px !important;
}

.mes .mes_block {
  background-color: var(--浅灰) !important;
  box-shadow: inset 0 1px 0 var(--边框色), 0 1px 0 var(--边框色) !important;
  /* 保持其余样式不变 */
  border: none !important;
  border-radius: 0 0 24px 24px !important;
  padding: 0 !important;
  width: 100% !important;
  position: relative !important;
}

.mes .mes_block::before { display: none !important; }

@media (max-width: 768px) {
  .mes .mesAvatarWrapper { padding: 25px 20px 7px 20px !important; }
  .mes .mesAvatarWrapper::before { height: 120px; }
  .mes .avatar img { width: 70px !important; height: 70px !important; min-width: 70px !important; min-height: 70px !important; }
  .mesAvatarWrapper .avatar { max-width: 70px !important; max-height: 70px !important; }
}

/* 装饰贴纸 (在暗色模式下通常不需要修改) */
.mes[is_user="false"] .mes_block::after {
  content: ''; position: absolute; top: 10px; left: -29px; width: 131px; height: 69px;
  background-image: url('https://pic1.imgdb.cn/item/68df4882c5157e1a8852371d.png');
  background-size: contain; background-repeat: no-repeat; background-position: center;
  pointer-events: none; z-index: 100;
}
.mes[is_user="false"]::before {
  content: ''; position: absolute; top: -11px; left: -41px; width: 130px; height: 145px;
  background-image: url(https://pic1.imgdb.cn/item/68df4f10c5157e1a88524b66.png);
  background-size: contain; background-repeat: no-repeat; background-position: center;
  pointer-events: none; z-index: 10; transform: rotate(23deg);
  filter: drop-shadow(2px 2px 4px rgba(0, 0, 0, 0.1));
}
.mes[is_user="true"]::before {
  content: ''; position: absolute; top: -38px; right: -15px; width: 110px; height: 110px;
  background-image: url('https://pic1.imgdb.cn/item/68df510ac5157e1a885253c2.png');
  background-size: contain; background-repeat: no-repeat; background-position: center;
  pointer-events: none; z-index: 10; transform: rotate(10deg);
}

.mes .mes_text {
  background-color: var(--浅灰) !important;
  /* 保持其余样式不变 */
  padding: 20px 16px !important;
  width: 100% !important;
  line-height: 1.6 !important;
}

.mes_buttons {
  background-color: var(--浅灰) !important;
  border-top: 1px solid var(--边框色) !important;
  /* 保持其余样式不变 */
  display: flex !important;
  align-items: center !important;
  gap: 16px !important;
  padding: 8px 16px 12px 16px !important;
}

.mes_button {
  color: var(--深灰) !important;
  font-size: 16px !important;
  cursor: pointer;
  transition: color 0.2s ease;
}
.mes_button:hover { color: var(--黑色) !important; }

.timestamp {
  background-color: var(--浅灰) !important;
  color: var(--深灰) !important;
  /* 保持其余样式不变 */
  padding: 4px 16px 12px 16px !important;
  font-size: 10px !important;
  text-transform: uppercase;
}

/* ===== 最终修复 & 视觉优化 (夜间模式) ===== */
.inline-drawer-content, #extensions_settings > div, .form_group, .standoutHeader,
.inline-drawer-header, div[style*="background-image: linear-gradient"], .swipper_button,
.drawer-content select, .standoutHeader.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4 {
  background-color: var(--浅灰) !important;
  background-image: none !important;
  border-color: var(--边框色) !important;
  box-shadow: none !important;
}

input[type="range"] { -webkit-appearance: none; appearance: none; width: 100%; background: transparent; cursor: pointer; }
input[type="range"]::-webkit-slider-runnable-track { width: 100%; height: 4px; background: var(--边框色) !important; border-radius: 2px; }
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none; appearance: none; margin-top: -6px; height: 16px; width: 16px;
  background-color: var(--黑色) !important;
  border: 1px solid var(--深灰) !important;
  border-radius: 50%;
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action { color: #a0a4ab !important; }

.character_select, .group_select, .tag, .inline-drawer-toggle, .extension_button,
.standoutHeader, button, .menu_button, input, textarea, select, #show_more_messages,
.mes_reasoning_header, .mes_reasoning {
  font-size: 12px !important; border-radius: 6px !important; margin-top: 4px !important; margin-bottom: 4px !important;
  background-color: var(--浅灰) !important;
  color: var(--黑色) !important;
  border: 1px solid var(--边框色) !important;
}
button, .menu_button {
    background-color: var(--中灰) !important;
}

h1, h2, h3, h4 { color: var(--黑色) !important; font-size: 14px !important; font-weight: 600 !important; }

pre, code {
  background-color: var(--主色调) !important;
  color: var(--黑色) !important;
  border: 1px solid var(--边框色) !important;
  border-radius: 4px !important;
  font-size: 11px !important;
  padding: 2px 5px !important;
}

::-webkit-scrollbar { width: 6px; background-color: transparent; }
::-webkit-scrollbar-thumb { background-color: var(--边框色) !important; border-radius: 10px; }
::-webkit-scrollbar-thumb:hover { background-color: var(--中灰) !important; }

input[type="checkbox"] {
  -webkit-appearance: none !important; appearance: none !important;
  width: 16px !important; height: 16px !important; margin: 0 8px 0 0 !important;
  flex-shrink: 0 !important; border: 1.5px solid var(--中灰) !important;
  border-radius: 3px !important; background: var(--浅灰) !important;
  cursor: pointer !important; position: relative !important; transition: all 0.2s ease !important;
}
input[type="checkbox"]:checked {
  background-color: var(--ins蓝) !important;
  border-color: var(--ins蓝) !important;
}
label:has(input[type="checkbox"])::before { display: none !important; }
label:has(input[type="checkbox"]) {
  display: flex !important; align-items: center !important;
  width: 100% !important; margin-bottom: 4px !important; padding: 4px 6px !important;
  border-radius: 4px; cursor: pointer; transition: background-color 0.2s ease;
}
label:has(input[type="checkbox"]):hover { background-color: var(--主色调); }

.reasoning_edit_textarea, .edit_textarea {
    padding: 5px; margin: 0; outline: none;
    background-color: rgba(255, 255, 255, 0.05);
    color: var(--黑色);
    line-height: calc(var(--mainFontSize) + .25rem);
    max-height: 75vh; max-height: 75dvh;
    field-sizing: content;
}

/* ===九、思维链美化 (夜间模式)=== */
.mes_reasoning_container { padding: 0 16px 16px 16px; }
.mes_reasoning_summary { list-style: none; cursor: pointer; display: flex !important; align-items: center; }
.mes_reasoning_header {
    cursor: pointer; position: relative; user-select: none; margin: 0.5em 2px;
    padding: 7px 14px; padding-right: calc(0.7em + 14px);
    border-radius: 5px;
    background-color: var(--主色调) !important; /* 修改背景色 */
    font-size: calc(var(--mainFontSize) * 0.9);
    align-items: baseline;
}
.mes_reasoning_header_title { font-size: 0 !important; }
.mes_reasoning_header_title::before {
  content: '开小差中...'; font-size: 12px;
  color: var(--深灰);
  font-weight: 500;
}
.mes_reasoning_arrow { font-size: 0 !important; }
.mes_reasoning_arrow::before {
  content: '›'; font-size: 18px;
  color: var(--中灰);
  margin-left: 8px; display: inline-block;
  transition: transform 0.3s ease; line-height: 1;
}
details[open] .mes_reasoning_arrow::before { transform: rotate(90deg); }
.mes_reasoning {
  margin-top: 8px; padding: 12px 15px;
  background-color: var(--主色调) !important; /* 使用更深的背景 */
  border-left: 3px solid var(--中灰); /* 左侧指示线 */
  border-radius: 0 8px 8px 0;
  color: var(--黑色) !important;
  font-family: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, Courier, monospace;
  font-size: 12px; line-height: 1.6;
  white-space: pre-wrap; word-break: break-all;
}

textarea {
    width: 100%; resize: vertical; display: block;
    background-color: var(--浅灰) !important; /* 确保背景色统一 */
    outline: none;
    border: 1px solid var(--边框色) !important; /* 使用主题变量 */
    border-radius: 5px;
    color: var(--黑色) !important; /* 使用主题变量 */
    font-size: var(--mainFontSize);
    font-family: var(--mainFontFamily);
    padding: 5px 10px;
    max-height: 90vh; max-height: 90dvh;
}
.neo-range-input {
    display: block; cursor: text;
    background-color: var(--浅灰) !important;
    border: 1px solid var(--边框色) !important; /* 使用主题变量 */
    border-radius: 0 0 5px 5px;
    padding: 2px; padding-left: 1em; padding-top: 5px;
    text-align: center; width: 100%;
}
.mes_text blockquote, .mes_reasoning blockquote {
    border-left: 3px solid rgb(80 83 86);
    padding-left: 10px;
    background-color: var(--black30a);
    margin: 0;
}
.welcomeRecent .recentChatList .recentChat {
    background-color: #0c0c0cc9;
    display: flex;
    flex-direction: row;
    align-items: center;
    padding: 5px 10px;
    border-radius: 10px;
    cursor: pointer;
    gap: 10px;
    border: 1px solid var(--SmartThemeBorderColor);
}
